/**
 * Writes all project source files into one text file for copy/paste or archival.
 * Run from repo root: node scripts/export-source-bundle.mjs
 */
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, "..");
const OUT_DIR = path.join(ROOT, "_export");
const OUT_FILE = path.join(OUT_DIR, "SOURCE_BUNDLE.txt");
const FILES = [
  "package.json",
  "firebase.json",
  "firestore.rules",
  "firestore.indexes.json",
  ".gitignore",
  "server/package.json",
  "server/env.example",
  "server/src/server.js",
  "server/src/firebase.js",
  "server/src/authMiddleware.js",
  "server/src/adminMiddleware.js",
  "server/src/attendanceCalculator.js",
  "server/src/recalcService.js",
  "server/src/routes/users.js",
  "server/src/routes/attendance.js",
  "server/src/routes/summary.js",
  "server/src/routes/admin.js",
  "client/package.json",
  "client/vite.config.js",
  "client/index.html",
  "client/.env.example",
  "client/src/main.jsx",
  "client/src/App.jsx",
  "client/src/styles.css",
  "client/src/firebase.js",
  "client/src/api.js",
  "client/src/AuthContext.jsx",
  "client/src/pages/Login.jsx",
  "client/src/pages/Register.jsx",
  "client/src/pages/Setup.jsx",
  "client/src/pages/Dashboard.jsx",
  "client/src/pages/History.jsx",
  "client/src/pages/Admin.jsx",
];

function banner(relPath) {
  return `\n\n${"=".repeat(80)}\nFILE: ${relPath}\n${"=".repeat(80)}\n\n`;
}
let bundle = `# mini-hcm — full source bundle\n# Generated by scripts/export-source-bundle.mjs\n# Copy each FILE section into your project at the path shown.\n`;
for (const rel of FILES) {
  const abs = path.join(ROOT, rel);
  if (!fs.existsSync(abs)) {
    bundle += banner(rel) + `[MISSING: ${rel}]\n`;
    continue;
  }
  const content = fs.readFileSync(abs, "utf8");
  bundle += banner(rel) + content;
}
fs.mkdirSync(OUT_DIR, { recursive: true });
fs.writeFileSync(OUT_FILE, bundle, "utf8");
console.log(`Wrote ${OUT_FILE} (${(bundle.length / 1024).toFixed(1)} KB)`);
